const items = $input.all();
const out = [];

for (const item of items) {
  const desc = item.json.description ?? '';
  // Extraer [asesor:+593XXXXXXXXX]
  const match = desc.match(/\[asesor:([^\]]+)\]/);
  const phone = match ? match[1].trim() : null;

  if (!phone) continue;

  // Fecha/hora legible en español
  const startRaw = item.json.start?.dateTime ?? item.json.start?.date;
  const startDate = new Date(startRaw);
  const fechaFormato = startDate.toLocaleDateString('es-EC', {
    weekday: 'long', day: '2-digit', month: 'long', year: 'numeric'
  });
  const horaFormato = item.json.start?.dateTime
    ? startDate.toLocaleTimeString('es-EC', { hour: '2-digit', minute: '2-digit' })
    : 'Todo el día';

  // Descripción limpia (sin la línea [asesor:...])
  const descLimpia = desc
    .replace(/\[asesor:[^\]]+\]/, '')
    .replace('[RECORDATORIO_ENVIADO]', '')
    .trim();

  out.push({
    json: {
      event_id:      item.json.id,
      event_title:   item.json.summary ?? 'Evento',
      fecha:         fechaFormato,
      hora:          horaFormato,
      ubicacion:     item.json.location ?? '',
      descripcion:   descLimpia,
      advisor_phone: phone,
      link:          item.json.htmlLink ?? '',
      description_original: desc
    }
  });
}

return out;

const base64Audio = $input.first().json.base64;
if (!base64Audio) {
  throw new Error('Evolution API no devolvió base64 del audio');
}
const extraer = $('Extraer Datos del Mensaje').item.json;
return [{
  json: {
    sender_phone: extraer.sender_phone,
    message_id: extraer.message_id,
    instance_name: extraer.instance_name,
    message_type: extraer.message_type
  },
  binary: {
    audio: {
      data: base64Audio,
      mimeType: 'audio/ogg',
      fileName: 'audio.ogg',
      fileExtension: 'ogg'
    }
  }
}];
